@allure.title("对话_简单判断stream为false时，推理结果准确性: {title}")
async def test_chat_accuracy(client,question,title):
    # 判断stream为false时，返回为ChatCompletion类型
    completion = await client.chat.completions.create(
        model=os_env('MODEL'),
        messages=[
        {
            "role": "user",
            "content": question
        }
        ],
        temperature=0,
        stream=False
    )
    print(f"正在测试: {title}")
    print(completion.usage)
    
    assert completion.object == 'chat.completion'
    assert isinstance(completion, ChatCompletion) == True
    assert completion.choices[0].message.role == 'assistant'
    assert is_nonsense_text(completion.choices[0].message.content, min_repeat=3, max_ratio=0.3) == False
    # assert is_low_diversity(completion.choices[0].message.content) == False
    assert text_accuracy(completion.choices[0].message.content) == True